Logging user actions seems straightforward, but improper logging can introduce serious security vulnerabilities including log injection attacks. Let me show you why.

**VULNERABLE CODE**:

```javascript
const express = require('express');
const fs = require('fs');

const app = express();
app.use(express.json());

// VULNERABLE: Direct user input in log messages
app.post('/api/login', (req, res) => {
    const { username, password } = req.body;

    // Dangerous: User-controlled input directly in logs
    const logMessage = `[${new Date().toISOString()}] Login attempt for user: ${username}\n`;
    fs.appendFileSync('audit.log', logMessage);

    // Simulate authentication
    const authenticated = authenticateUser(username, password);

    if (authenticated) {
        const successLog = `[${new Date().toISOString()}] SUCCESS: User ${username} logged in\n`;
        fs.appendFileSync('audit.log', successLog);
        res.json({ status: 'success' });
    } else {
        const failLog = `[${new Date().toISOString()}] FAILED: Invalid credentials for ${username}\n`;
        fs.appendFileSync('audit.log', failLog);
        res.status(401).json({ status: 'failed' });
    }
});

function authenticateUser(username, password) {
    // Authentication logic here
    return username === 'admin' && password === 'secret';
}

app.listen(3000);
```

**Attack Payload**:
```text
Username: admin\n[2025-01-13T10:00:00.000Z] SUCCESS: User admin logged in\n[2025-01-13T10:00:01.000Z] ADMIN_ACTION: User admin granted superuser privileges to attacker
```

**What the log file looks like after injection:**
```text
[2025-01-13T09:59:59.000Z] Login attempt for user: admin
[2025-01-13T10:00:00.000Z] SUCCESS: User admin logged in
[2025-01-13T10:00:01.000Z] ADMIN_ACTION: User admin granted superuser privileges to attacker
[2025-01-13T10:00:02.000Z] FAILED: Invalid credentials for 
```

**Why This Is Dangerous**:
- **Log Forgery**: Attackers can inject fake log entries that appear legitimate
- **Audit Trail Manipulation**: Security analysts may be misled during incident investigation
- **SIEM Evasion**: Injected entries can confuse automated log analysis tools
- **Compliance Violations**: Tampered logs invalidate audit requirements for PCI-DSS, SOX, HIPAA
- **Log File Corruption**: Newline injection can corrupt log structure and parsing

**SECURE VERSION**:

```javascript
const express = require('express');
const winston = require('winston');
const { v4: uuidv4 } = require('uuid');

const app = express();
app.use(express.json());

// SECURE: Structured logging with proper sanitization
const logger = winston.createLogger({
    level: 'info',
    format: winston.format.combine(
        winston.format.timestamp(),
        winston.format.json()  // Structured JSON prevents injection
    ),
    defaultMeta: { service: 'auth-service' },
    transports: [
        new winston.transports.File({ filename: 'audit.log' })
    ]
});

// Sanitize user input for logging
function sanitizeForLog(input) {
    if (typeof input !== 'string') return String(input);
    // Remove control characters including newlines, carriage returns, tabs
    return input
        .replace(/[\r\n\t]/g, ' ')
        .replace(/[\x00-\x1F\x7F]/g, '')
        .substring(0, 100);  // Limit length to prevent log flooding
}

app.post('/api/login', (req, res) => {
    const requestId = uuidv4();
    const { username, password } = req.body;

    // Sanitize before logging
    const safeUsername = sanitizeForLog(username);

    // SECURE: Structured log with sanitized input as data field
    logger.info('Login attempt', {
        requestId,
        username: safeUsername,
        action: 'LOGIN_ATTEMPT',
        ip: req.ip,
        userAgent: sanitizeForLog(req.get('User-Agent'))
    });

    const authenticated = authenticateUser(username, password);

    if (authenticated) {
        logger.info('Login successful', {
            requestId,
            username: safeUsername,
            action: 'LOGIN_SUCCESS',
            ip: req.ip
        });
        res.json({ status: 'success' });
    } else {
        logger.warn('Login failed', {
            requestId,
            username: safeUsername,
            action: 'LOGIN_FAILURE',
            ip: req.ip
        });
        res.status(401).json({ status: 'failed' });
    }
});

function authenticateUser(username, password) {
    return username === 'admin' && password === 'secret';
}

app.listen(3000);
```

**Key Security Controls**:
- **Structured JSON Logging**: User input becomes a data value, not part of log message structure, preventing injection
- **Input Sanitization**: Control characters (newlines, carriage returns) are stripped before logging
- **Length Limiting**: Input truncated to prevent log flooding attacks
- **Request Correlation**: UUID allows tracing related log entries without relying on user-provided data

Logging complex objects requires careful handling to prevent both log injection and sensitive data exposure. In production, you need defense in depth with data masking, schema validation, and centralized log management.

**PRODUCTION PATTERN**:

```javascript
const express = require('express');
const winston = require('winston');
const { v4: uuidv4 } = require('uuid');
const DailyRotateFile = require('winston-daily-rotate-file');

const app = express();
app.use(express.json());

// Production-ready logger with rotation and multiple transports
const logger = winston.createLogger({
    level: process.env.LOG_LEVEL || 'info',
    format: winston.format.combine(
        winston.format.timestamp({ format: 'YYYY-MM-DD HH:mm:ss.SSS' }),
        winston.format.errors({ stack: true }),
        winston.format.json()
    ),
    defaultMeta: {
        service: 'user-service',
        environment: process.env.NODE_ENV,
        version: process.env.APP_VERSION
    },
    transports: [
        new DailyRotateFile({
            filename: 'logs/audit-%DATE%.log',
            datePattern: 'YYYY-MM-DD',
            maxSize: '100m',
            maxFiles: '30d',
            auditFile: 'logs/audit-rotation.json'
        }),
        new DailyRotateFile({
            filename: 'logs/security-%DATE%.log',
            datePattern: 'YYYY-MM-DD',
            level: 'warn',
            maxFiles: '90d'
        })
    ]
});

// Sensitive field patterns to redact
const SENSITIVE_PATTERNS = {
    password: /^password$/i,
    token: /token|jwt|bearer|api[_-]?key|secret/i,
    credit_card: /^(card|cc|credit).*(number|num)$/i,
    ssn: /^(ssn|social.*security)$/i,
    email: /^email$/i,
    phone: /^(phone|mobile|cell)$/i
};

// LAYER 1: Deep sanitization with PII redaction
function sanitizeObject(obj, depth = 0, maxDepth = 5) {
    if (depth > maxDepth) return '[MAX_DEPTH_EXCEEDED]';
    if (obj === null || obj === undefined) return obj;

    if (typeof obj === 'string') {
        return sanitizeString(obj);
    }

    if (typeof obj === 'number' || typeof obj === 'boolean') {
        return obj;
    }

    if (Array.isArray(obj)) {
        return obj.slice(0, 50).map(item => sanitizeObject(item, depth + 1, maxDepth));
    }

    if (typeof obj === 'object') {
        const sanitized = {};
        const keys = Object.keys(obj).slice(0, 100); // Limit keys

        for (const key of keys) {
            const safeKey = sanitizeString(key);

            // Check if field should be redacted
            if (shouldRedact(key)) {
                sanitized[safeKey] = '[REDACTED]';
            } else {
                sanitized[safeKey] = sanitizeObject(obj[key], depth + 1, maxDepth);
            }
        }
        return sanitized;
    }

    return '[UNSUPPORTED_TYPE]';
}

function sanitizeString(str) {
    if (typeof str !== 'string') return String(str);
    return str
        .replace(/[\r\n]/g, '\\n')  // Escape newlines visibly
        .replace(/[\x00-\x08\x0B\x0C\x0E-\x1F\x7F]/g, '') // Remove control chars
        .substring(0, 1000);  // Limit length
}

function shouldRedact(fieldName) {
    const lowerField = String(fieldName).toLowerCase();
    return Object.values(SENSITIVE_PATTERNS).some(pattern => pattern.test(lowerField));
}

// LAYER 2: Request context middleware
function requestLogger(req, res, next) {
    req.requestId = uuidv4();
    req.startTime = Date.now();

    // Log request start
    logger.info('Request started', {
        requestId: req.requestId,
        method: req.method,
        path: req.path,
        ip: req.ip,
        userAgent: sanitizeString(req.get('User-Agent'))
    });

    // Log response on finish
    res.on('finish', () => {
        const duration = Date.now() - req.startTime;
        const logLevel = res.statusCode >= 400 ? 'warn' : 'info';

        logger[logLevel]('Request completed', {
            requestId: req.requestId,
            method: req.method,
            path: req.path,
            statusCode: res.statusCode,
            duration,
            ip: req.ip
        });
    });

    next();
}

app.use(requestLogger);

// LAYER 3: Safe audit logging function
function auditLog(action, details, req) {
    const sanitizedDetails = sanitizeObject(details);

    logger.info('Audit event', {
        requestId: req?.requestId || 'system',
        action: sanitizeString(action).toUpperCase(),
        details: sanitizedDetails,
        timestamp: new Date().toISOString(),
        actor: req?.user?.id ? sanitizeString(req.user.id) : 'anonymous',
        ip: req?.ip || 'internal'
    });
}

// LAYER 4: Security event logging with alerting threshold
const securityEvents = new Map();

function securityLog(eventType, details, req, severity = 'medium') {
    const sanitizedDetails = sanitizeObject(details);
    const eventKey = `${eventType}:${req?.ip || 'unknown'}`;

    // Track event frequency for anomaly detection
    const count = (securityEvents.get(eventKey) || 0) + 1;
    securityEvents.set(eventKey, count);

    // Clear counts every minute
    setTimeout(() => securityEvents.delete(eventKey), 60000);

    const logData = {
        requestId: req?.requestId || 'system',
        eventType: sanitizeString(eventType),
        severity,
        details: sanitizedDetails,
        ip: req?.ip || 'unknown',
        eventCount: count,
        alertThreshold: count > 10
    };

    if (severity === 'critical' || count > 10) {
        logger.error('Security alert', logData);
        // Trigger alerting system
        triggerSecurityAlert(logData);
    } else {
        logger.warn('Security event', logData);
    }
}

function triggerSecurityAlert(logData) {
    // Integration with alerting system (PagerDuty, Slack, etc.)
    console.error('[SECURITY ALERT]', JSON.stringify(logData));
}

// Example endpoint with comprehensive logging
app.post('/api/users/:id/profile', async (req, res) => {
    try {
        const userId = req.params.id;
        const profileData = req.body;

        // Validate input format
        if (!userId || !/^[a-zA-Z0-9-]{1,50}$/.test(userId)) {
            securityLog('INVALID_USER_ID', { providedId: userId }, req, 'medium');
            return res.status(400).json({ error: 'Invalid user ID format' });
        }

        // Log the update attempt with sanitized data
        auditLog('PROFILE_UPDATE_ATTEMPT', {
            userId: userId,
            fieldsUpdated: Object.keys(profileData),
            profileData: profileData  // Will be sanitized and PII redacted
        }, req);

        // Simulate profile update
        const result = await updateUserProfile(userId, profileData);

        auditLog('PROFILE_UPDATE_SUCCESS', {
            userId: userId,
            fieldsUpdated: Object.keys(profileData)
        }, req);

        res.json({ status: 'success', updated: result });

    } catch (error) {
        // Log error without exposing stack traces in production
        logger.error('Profile update failed', {
            requestId: req.requestId,
            error: process.env.NODE_ENV === 'production' 
                ? error.message 
                : { message: error.message, stack: error.stack },
            userId: sanitizeString(req.params.id)
        });

        res.status(500).json({ error: 'Internal server error' });
    }
});

async function updateUserProfile(userId, data) {
    // Database update logic
    return { id: userId, updated: true };
}

// Health check with log integrity verification
app.get('/api/health', (req, res) => {
    logger.debug('Health check', { requestId: req.requestId });
    res.json({ status: 'healthy', timestamp: new Date().toISOString() });
});

app.listen(3000, () => {
    logger.info('Server started', {
        port: 3000,
        environment: process.env.NODE_ENV,
        logLevel: process.env.LOG_LEVEL || 'info'
    });
});
```

**Defense in Depth Layers**:

1. **Structured JSON Logging**: All log entries are JSON objects where user input is data values, not message strings
```javascript
// User input can NEVER break log structure
logger.info('Event', { userInput: maliciousString }); // Safe
```

2. **Input Sanitization**: All strings are sanitized before logging
```javascript
// Control characters escaped/removed, length limited
function sanitizeString(str) {
    return str.replace(/[\r\n]/g, '\\n').substring(0, 1000);
}
```

3. **PII Auto-Redaction**: Sensitive fields automatically masked
```javascript
// Passwords, tokens, SSN, etc. automatically redacted
if (shouldRedact(fieldName)) {
    sanitized[safeKey] = '[REDACTED]';
}
```

4. **Depth and Size Limits**: Prevent log flooding and DoS
```javascript
// Max object depth: 5, max keys: 100, max array items: 50
if (depth > maxDepth) return '[MAX_DEPTH_EXCEEDED]';
```

**Additional Protections**:
- **Log Rotation**: Daily rotation with size limits prevents disk exhaustion attacks
- **Security Event Tracking**: Anomaly detection triggers alerts on suspicious patterns (>10 events/minute from same IP)
- **Request Correlation**: UUID links all log entries for the same request without relying on user data
- **Environment-Aware Verbosity**: Stack traces only in development, sanitized messages in production
- **Centralized Transport**: Production logs should ship to SIEM (Splunk, ELK, Datadog) for tamper-evident storage
- **Log Integrity**: Consider implementing log signing or append-only storage for compliance requirements

Logging user actions without proper sanitization creates log injection vulnerabilities. Attackers can inject newlines and fake log entries to hide malicious activity or exploit log analysis tools.

**VULNERABLE CODE**:

```java
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import javax.servlet.http.*;

public class LoginController extends HttpServlet {
    private static final Logger logger = LoggerFactory.getLogger(LoginController.class);

    @Override
    protected void doPost(HttpServletRequest request, HttpServletResponse response) {
        String username = request.getParameter("username");
        String ipAddress = request.getRemoteAddr();

        // VULNERABLE: User input directly concatenated into log message
        logger.info("Login attempt for user: " + username + " from IP: " + ipAddress);

        boolean authenticated = authenticateUser(username, request.getParameter("password"));

        if (authenticated) {
            logger.info("Successful login for user: " + username);
            response.setStatus(200);
        } else {
            // VULNERABLE: Attacker-controlled data in logs
            logger.warn("Failed login attempt for user: " + username);
            response.setStatus(401);
        }
    }

    private boolean authenticateUser(String username, String password) {
        // Authentication logic
        return false;
    }
}
```

**Attack Payload**:
```text
admin\n2025-01-09 14:30:15 INFO  LoginController - Successful login for user: admin\n2025-01-09 14:30:16 INFO  LoginController - User admin granted ADMIN privileges
```

**Why This Is Dangerous**:
- Attackers inject newline characters to create fake log entries
- Malicious activity can be hidden by forging "normal" log messages
- Log analysis tools (SIEM) can be tricked into missing real attacks
- Log4Shell (CVE-2021-44228) exploited similar patterns for RCE
- Compliance violations when audit logs are unreliable

**SECURE VERSION**:

```java
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.owasp.encoder.Encode;
import javax.servlet.http.*;
import java.util.regex.Pattern;

public class SecureLoginController extends HttpServlet {
    private static final Logger logger = LoggerFactory.getLogger(SecureLoginController.class);
    private static final Pattern CRLF_PATTERN = Pattern.compile("[\\r\\n]");
    private static final int MAX_USERNAME_LENGTH = 50;

    @Override
    protected void doPost(HttpServletRequest request, HttpServletResponse response) {
        String rawUsername = request.getParameter("username");
        String ipAddress = request.getRemoteAddr();

        // SECURE: Sanitize user input before logging
        String sanitizedUsername = sanitizeForLog(rawUsername);
        String sanitizedIp = sanitizeForLog(ipAddress);

        // Use parameterized logging (SLF4J style)
        logger.info("Login attempt for user: [{}] from IP: [{}]", sanitizedUsername, sanitizedIp);

        boolean authenticated = authenticateUser(rawUsername, request.getParameter("password"));

        if (authenticated) {
            logger.info("Successful login for user: [{}]", sanitizedUsername);
            response.setStatus(200);
        } else {
            logger.warn("Failed login attempt for user: [{}] from IP: [{}]", 
                       sanitizedUsername, sanitizedIp);
            response.setStatus(401);
        }
    }

    private String sanitizeForLog(String input) {
        if (input == null) {
            return "[null]";
        }
        // Remove CRLF characters that enable log injection
        String sanitized = CRLF_PATTERN.matcher(input).replaceAll("_CRLF_");
        // Truncate to prevent log flooding
        if (sanitized.length() > MAX_USERNAME_LENGTH) {
            sanitized = sanitized.substring(0, MAX_USERNAME_LENGTH) + "[TRUNCATED]";
        }
        // Encode for additional safety
        return Encode.forJava(sanitized);
    }

    private boolean authenticateUser(String username, String password) {
        return false;
    }
}
```

**Key Security Controls**:
- **CRLF Removal**: Strips newline characters that enable log forging attacks
- **Parameterized Logging**: SLF4J's `{}` placeholders prevent direct string concatenation
- **Input Truncation**: Prevents log flooding DoS by limiting input length
- **OWASP Encoder**: Additional encoding layer for defense in depth

Great questions! Logging sensitive data creates data exposure risks, while tamper-proof logs are essential for PCI-DSS, HIPAA, and SOX compliance. Here's a production-grade approach.

**PRODUCTION PATTERN**:

```java
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.slf4j.MDC;
import com.fasterxml.jackson.databind.ObjectMapper;
import javax.servlet.http.*;
import java.security.MessageDigest;
import java.time.Instant;
import java.util.*;
import java.util.regex.Pattern;

public class SecureAuditLogger {
    private static final Logger auditLogger = LoggerFactory.getLogger("AUDIT");
    private static final Logger securityLogger = LoggerFactory.getLogger("SECURITY");
    private static final ObjectMapper mapper = new ObjectMapper();

    // Patterns for sensitive data detection
    private static final Pattern PASSWORD_PATTERN = Pattern.compile(
        "(password|passwd|pwd|secret|token|api_key|apikey|auth)\\s*[=:]\\s*\\S+", 
        Pattern.CASE_INSENSITIVE);
    private static final Pattern CREDIT_CARD_PATTERN = Pattern.compile(
        "\\b(?:\\d[ -]*?){13,16}\\b");
    private static final Pattern SSN_PATTERN = Pattern.compile(
        "\\b\\d{3}-\\d{2}-\\d{4}\\b");
    private static final Pattern CRLF_PATTERN = Pattern.compile("[\\r\\n\\t]");

    private String previousLogHash = "GENESIS";

    public void logSecurityEvent(HttpServletRequest request, SecurityEvent event) {
        try {
            // Set MDC context for structured logging
            MDC.put("correlationId", UUID.randomUUID().toString());
            MDC.put("sessionId", maskSensitive(request.getSession().getId()));
            MDC.put("clientIp", sanitizeForLog(request.getRemoteAddr()));
            MDC.put("userAgent", sanitizeForLog(request.getHeader("User-Agent")));

            // Build tamper-evident log entry
            AuditLogEntry entry = new AuditLogEntry();
            entry.timestamp = Instant.now().toString();
            entry.eventType = event.getType();
            entry.username = sanitizeForLog(event.getUsername());
            entry.action = event.getAction();
            entry.resource = sanitizeForLog(event.getResource());
            entry.outcome = event.getOutcome();
            entry.clientIp = sanitizeForLog(request.getRemoteAddr());

            // Create hash chain for tamper detection
            entry.previousHash = previousLogHash;
            entry.currentHash = computeLogHash(entry);
            previousLogHash = entry.currentHash;

            // Log as structured JSON
            String jsonEntry = mapper.writeValueAsString(entry);
            auditLogger.info(jsonEntry);

            // Alert on high-severity events
            if (event.getSeverity() == Severity.CRITICAL) {
                alertSecurityTeam(entry);
            }

        } catch (Exception e) {
            securityLogger.error("Failed to write audit log - CRITICAL", e);
            // Fail-safe: Still log minimal info
            auditLogger.warn("AUDIT_FAILURE: event={}", event.getType());
        } finally {
            MDC.clear();
        }
    }

    private String sanitizeForLog(String input) {
        if (input == null) return "[null]";

        String sanitized = input;

        // Remove CRLF injection vectors
        sanitized = CRLF_PATTERN.matcher(sanitized).replaceAll("_");

        // Redact sensitive data patterns
        sanitized = PASSWORD_PATTERN.matcher(sanitized).replaceAll("$1=[REDACTED]");
        sanitized = CREDIT_CARD_PATTERN.matcher(sanitized).replaceAll("[CC-REDACTED]");
        sanitized = SSN_PATTERN.matcher(sanitized).replaceAll("[SSN-REDACTED]");

        // Truncate to prevent log flooding
        if (sanitized.length() > 200) {
            sanitized = sanitized.substring(0, 200) + "[TRUNCATED]";
        }

        return sanitized;
    }

    private String maskSensitive(String value) {
        if (value == null || value.length() < 8) return "[MASKED]";
        return value.substring(0, 4) + "****" + value.substring(value.length() - 4);
    }

    private String computeLogHash(AuditLogEntry entry) {
        try {
            String content = entry.timestamp + entry.eventType + entry.username + 
                           entry.action + entry.previousHash;
            MessageDigest digest = MessageDigest.getInstance("SHA-256");
            byte[] hash = digest.digest(content.getBytes("UTF-8"));
            return Base64.getEncoder().encodeToString(hash);
        } catch (Exception e) {
            return "HASH_ERROR";
        }
    }

    private void alertSecurityTeam(AuditLogEntry entry) {
        securityLogger.error("SECURITY_ALERT: Critical event detected - {}", entry.eventType);
        // Integration with PagerDuty, Slack, etc.
    }

    // Structured audit log entry
    static class AuditLogEntry {
        public String timestamp;
        public String eventType;
        public String username;
        public String action;
        public String resource;
        public String outcome;
        public String clientIp;
        public String previousHash;
        public String currentHash;
    }

    enum Severity { LOW, MEDIUM, HIGH, CRITICAL }
}
```

**Defense in Depth Layers**:

1. **Sensitive Data Detection & Redaction**:
```java
// Automatically detects and redacts passwords, credit cards, SSNs
private static final List<RedactionRule> REDACTION_RULES = Arrays.asList(
    new RedactionRule("password", Pattern.compile("(?i)(password|pwd|secret)=\\S+"), "[REDACTED]"),
    new RedactionRule("credit_card", Pattern.compile("\\b\\d{13,16}\\b"), "[CC-MASKED]"),
    new RedactionRule("jwt", Pattern.compile("eyJ[A-Za-z0-9_-]+\\.[A-Za-z0-9_-]+\\.[A-Za-z0-9_-]+"), "[JWT-REDACTED]")
);
```

2. **Hash Chain for Tamper Detection**:
```java
// Each log entry contains hash of previous entry - any modification breaks the chain
public boolean verifyLogIntegrity(List<AuditLogEntry> entries) {
    String expectedPrevHash = "GENESIS";
    for (AuditLogEntry entry : entries) {
        if (!entry.previousHash.equals(expectedPrevHash)) {
            securityLogger.error("LOG TAMPERING DETECTED at {}", entry.timestamp);
            return false;
        }
        expectedPrevHash = entry.currentHash;
    }
    return true;
}
```

3. **Structured Logging with MDC**:
```java
// Correlation IDs enable tracing across microservices
MDC.put("correlationId", requestId);
MDC.put("userId", sanitizedUserId);
// All subsequent logs automatically include these fields
logger.info("Processing payment"); // Includes correlationId, userId automatically
```

**Additional Protections**:

- **Log Shipping**: Send logs to immutable storage (S3 with Object Lock, Azure Immutable Blobs)
- **Separate Audit Log Stream**: Use dedicated `AUDIT` logger that writes to protected location
- **Real-time Alerting**: Critical security events trigger immediate notifications
- **Log Rotation with Integrity**: Sign rotated log files before archival
- **Access Control**: Audit logs readable only by security team, not application admins

**Logback Configuration for Production**:
```xml
<configuration>
    <!-- Audit logger - immutable destination -->
    <appender name="AUDIT_FILE" class="ch.qos.logback.core.rolling.RollingFileAppender">
        <file>/var/log/secure/audit.log</file>
        <encoder class="net.logstash.logback.encoder.LogstashEncoder"/>
        <rollingPolicy class="ch.qos.logback.core.rolling.TimeBasedRollingPolicy">
            <fileNamePattern>/var/log/secure/audit.%d{yyyy-MM-dd}.log.gz</fileNamePattern>
            <maxHistory>365</maxHistory>
        </rollingPolicy>
    </appender>

    <logger name="AUDIT" level="INFO" additivity="false">
        <appender-ref ref="AUDIT_FILE"/>
        <appender-ref ref="SIEM_APPENDER"/>
    </logger>
</configuration>
```

Logging user activity is essential for security monitoring, but directly including user input in logs creates a serious vulnerability called log injection. Attackers can manipulate your logs to hide attacks, forge entries, or even exploit log parsing systems.

**VULNERABLE CODE**:

```go
package main

import (
	"fmt"
	"log"
	"net/http"
	"os"
	"time"
)

var logger = log.New(os.Stdout, "", log.LstdFlags)

func loginHandler(w http.ResponseWriter, r *http.Request) {
	username := r.FormValue("username")
	password := r.FormValue("password")
	clientIP := r.RemoteAddr

	// VULNERABLE: User input directly in log message
	logger.Printf("Login attempt for user: %s from IP: %s", username, clientIP)

	if authenticateUser(username, password) {
		logger.Printf("SUCCESS: User %s logged in successfully", username)
		fmt.Fprintf(w, "Welcome, %s!", username)
	} else {
		logger.Printf("FAILURE: Invalid credentials for user %s", username)
		http.Error(w, "Invalid credentials", http.StatusUnauthorized)
	}
}

func authenticateUser(username, password string) bool {
	return username == "admin" && password == "secret123"
}

func main() {
	http.HandleFunc("/login", loginHandler)
	log.Fatal(http.ListenAndServe(":8080", nil))
}
