  const { username, password } = req.body;

  // Dangerous: username is user-controlled
  console.log(`[INFO] Login attempt for user: ${username}`);

  // Also logged to file without sanitization
  const logEntry = `${new Date().toISOString()} - LOGIN - User: ${username}\n`;
  fs.appendFileSync('app.log', logEntry);

  // Authentication logic
  if (authenticateUser(username, password)) {
    console.log(`[INFO] Successful login for user: ${username}`);
    res.json({ success: true });
  } else {
    console.log(`[WARN] Failed login for user: ${username}`);
    res.status(401).json({ error: 'Invalid credentials' });
  }
});

function authenticateUser(username, password) {
  // Simplified auth check
  return username === 'admin' && password === 'secret';
}

app.listen(3000);
```

**Attack Payload**:
```text
admin\n[INFO] 2024-01-15T10:30:00Z - Successful login for user: admin\n[INFO] 2024-01-15T10:30:01Z - Admin granted superuser privileges
```

**Another Attack - ANSI Escape Injection**:
