Logging complex objects requires careful handling to prevent both injection attacks and sensitive data leakage. Production systems need comprehensive sanitization, PII redaction, and tamper-evident logging.

**PRODUCTION PATTERN**:

```javascript
const express = require('express');
const winston = require('winston');
const crypto = require('crypto');
const { v4: uuidv4 } = require('uuid');

const app = express();
app.use(express.json());

// Sensitive field patterns to redact
const SENSITIVE_PATTERNS = [
  /password/i, /secret/i, /token/i, /api[_-]?key/i,
  /credit[_-]?card/i, /ssn/i, /authorization/i,
  /session/i, /cookie/i, /bearer/i
];

// Deep sanitization for complex objects
function deepSanitize(obj, depth = 0, maxDepth = 5) {
  if (depth > maxDepth) return '[MAX_DEPTH_EXCEEDED]';
  if (obj === null || obj === undefined) return obj;

  if (typeof obj === 'string') {
    return sanitizeString(obj);
  }

  if (Array.isArray(obj)) {
    return obj.slice(0, 100).map(item => deepSanitize(item, depth + 1, maxDepth));
  }

  if (typeof obj === 'object') {
    const sanitized = {};
    const keys = Object.keys(obj).slice(0, 50); // Limit keys

    for (const key of keys) {
      const safeKey = sanitizeString(key);

      // Redact sensitive fields
      if (SENSITIVE_PATTERNS.some(pattern => pattern.test(key))) {
        sanitized[safeKey] = '[REDACTED]';
      } else {
        sanitized[safeKey] = deepSanitize(obj[key], depth + 1, maxDepth);
      }
    }
    return sanitized;
  }

  return obj;
}

function sanitizeString(input) {
  if (typeof input !== 'string') return String(input);
  return input
    .replace(/[\r\n]/g, '\\n')              // Escape newlines visibly
    .replace(/[\x00-\x08\x0B\x0C\x0E-\x1F\x7F]/g, '') // Remove control chars
    .replace(/\x1b\[[0-9;]*[a-zA-Z]/g, '')  // Remove ANSI codes
    .substring(0, 1000);                     // Limit length
}

function sanitizeStackTrace(stack) {
  if (!stack) return 'No stack trace';
  return stack
    .split('\n')
    .slice(0, 15)                            // Limit stack depth
    .map(line => sanitizeString(line))
    .join(' | ');                            // Join with safe delimiter
}

// Calculate log entry hash for tamper detection
function calculateLogHash(entry, previousHash) {
  const data = JSON.stringify(entry) + (previousHash || '');
  return crypto.createHash('sha256').update(data).digest('hex').substring(0, 16);
}

let previousLogHash = null;

// Production logger with integrity tracking
const logger = winston.createLogger({
  level: process.env.LOG_LEVEL || 'info',
  format: winston.format.combine(
    winston.format.timestamp({ format: 'YYYY-MM-DDTHH:mm:ss.SSSZ' }),
    winston.format.printf(({ timestamp, level, message, ...meta }) => {
      const entry = {
        timestamp,
        level,
        message,
        ...meta,
        integrity: calculateLogHash({ timestamp, level, message, ...meta }, previousLogHash)
      };
      previousLogHash = entry.integrity;
      return JSON.stringify(entry);
    })
  ),
  transports: [
    new winston.transports.File({
      filename: 'app.log',
      maxsize: 10485760,  // 10MB
      maxFiles: 10,
      tailable: true
    })
  ]
});

// Secure request logging middleware
function secureRequestLogger(req, res, next) {
  req.requestId = uuidv4();
  req.startTime = Date.now();

  // Log sanitized request
  logger.info('Request received', {
    requestId: req.requestId,
    method: req.method,
    path: sanitizeString(req.path),
    query: deepSanitize(req.query),
    body: deepSanitize(req.body),
    clientIP: req.ip,
    userAgent: sanitizeString(req.get('User-Agent') || 'unknown')
  });

  // Log response on finish
  res.on('finish', () => {
    logger.info('Request completed', {
      requestId: req.requestId,
      statusCode: res.statusCode,
      duration: Date.now() - req.startTime
    });
  });

  next();
}

// Secure error handler
function secureErrorHandler(err, req, res, next) {
  const errorId = uuidv4();

  logger.error('Application error', {
    errorId,
    requestId: req.requestId,
    message: sanitizeString(err.message),
    stack: sanitizeStackTrace(err.stack),
    code: err.code || 'UNKNOWN',
    path: sanitizeString(req.path),
    method: req.method
  });

  // Return safe error to client
  res.status(err.status || 500).json({
    error: 'An error occurred',
    errorId  // Allow correlation without exposing details
  });
}

app.use(secureRequestLogger);

app.post('/api/process', (req, res, next) => {
  try {
    // Business logic that might throw
    const result = processData(req.body);
    res.json(result);
  } catch (err) {
    next(err);
  }
});

app.use(secureErrorHandler);

function processData(data) {
  // Simulated processing
  if (!data.value) {
    const error = new Error('Missing required field: value');
    error.status = 400;
    throw error;
  }
  return { processed: true };
}

app.listen(3000);
```

