  ),
  transports: [
    new winston.transports.File({ filename: 'app.log' }),
    new winston.transports.Console()
  ]
});

// Sanitize user input for logging
function sanitizeForLog(input) {
  if (typeof input !== 'string') {
    return String(input);
  }
  // Remove control characters, newlines, and limit length
  return input
    .replace(/[\x00-\x1F\x7F]/g, '') // Remove control characters
    .replace(/[\r\n]/g, ' ')          // Replace newlines with spaces
    .substring(0, 200);                // Limit length
}

app.get('/search', (req, res) => {
  const requestId = uuidv4();
  const searchTerm = sanitizeForLog(req.query.q || '');
  const username = sanitizeForLog(req.query.user || 'anonymous');

  // SECURE: Structured logging with sanitized input
  logger.info('Search request', {
    requestId,
    action: 'search',
    username,
    searchTerm,
    ip: req.ip,
    userAgent: sanitizeForLog(req.get('User-Agent') || 'unknown')
  });

  res.json({ results: [], query: req.query.q, requestId });
});

app.post('/login', (req, res) => {
  const requestId = uuidv4();
  const { username } = req.body;

  // SECURE: Never log passwords, sanitize username
  logger.info('Login attempt', {
    requestId,
    action: 'login_attempt',
    username: sanitizeForLog(username),
    ip: req.ip,
    timestamp: new Date().toISOString()
  });

  // Authentication logic...
  res.json({ success: true, requestId });
});

app.listen(3000);
```

**Key Security Controls**:
- **JSON Structured Logging**: User input becomes a JSON value, not part of the log structure, preventing injection
- **Input Sanitization**: Control characters and newlines stripped before logging
- **Length Limits**: Prevents log flooding attacks with extremely long inputs
- **Sensitive Data Protection**: Passwords never logged; PII minimized
- **Request Correlation**: UUID allows tracing requests across systems without exposing user data

Production logging across microservices requires a comprehensive security strategy. You need to protect against log injection, ensure log integrity, and safely aggregate logs without creating new attack vectors.

**PRODUCTION PATTERN**:

```javascript
const express = require('express');
const winston = require('winston');
const DailyRotateFile = require('winston-daily-rotate-file');
const crypto = require('crypto');
const { v4: uuidv4 } = require('uuid');

const app = express();
app.use(express.json());

// Environment configuration
const config = {
  serviceName: process.env.SERVICE_NAME || 'api-gateway',
  environment: process.env.NODE_ENV || 'development',
  logLevel: process.env.LOG_LEVEL || 'info',
  hmacSecret: process.env.LOG_HMAC_SECRET,
  maxLogFieldLength: 500,
  sensitiveFields: ['password', 'token', 'apiKey', 'secret', 'authorization', 'cookie', 'ssn', 'creditCard']
};

// Log integrity: HMAC signature for tamper detection
function signLogEntry(entry) {
  if (!config.hmacSecret) return entry;
  const signature = crypto
    .createHmac('sha256', config.hmacSecret)
    .update(JSON.stringify(entry))
    .digest('hex');
  return { ...entry, _signature: signature };
}

// Comprehensive input sanitizer
class LogSanitizer {
  static sanitizeString(input, maxLength = config.maxLogFieldLength) {
    if (input === null || input === undefined) return '[null]';
    if (typeof input !== 'string') {
      try {
        input = JSON.stringify(input);
      } catch {
        return '[unparseable]';
      }
    }

    return input
      .replace(/[\x00-\x08\x0B\x0C\x0E-\x1F\x7F]/g, '') // Remove control chars except \t\n\r
      .replace(/[\r\n\t]/g, ' ')                         // Normalize whitespace
      .replace(/\$\{[^}]*\}/g, '[EXPR_REMOVED]')         // Remove JNDI/template expressions
      .replace(/\{\{[^}]*\}\}/g, '[TEMPLATE_REMOVED]')   // Remove template injections
      .substring(0, maxLength);
  }

  static sanitizeObject(obj, depth = 0) {
    if (depth > 5) return '[MAX_DEPTH]';
    if (obj === null || obj === undefined) return obj;
    if (typeof obj !== 'object') return this.sanitizeString(String(obj));

    const sanitized = Array.isArray(obj) ? [] : {};

    for (const [key, value] of Object.entries(obj)) {
      const lowerKey = key.toLowerCase();

      // Redact sensitive fields
      if (config.sensitiveFields.some(f => lowerKey.includes(f))) {
        sanitized[key] = '[REDACTED]';
        continue;
      }

      if (typeof value === 'object' && value !== null) {
        sanitized[key] = this.sanitizeObject(value, depth + 1);
      } else {
        sanitized[key] = this.sanitizeString(String(value));
      }
    }

    return sanitized;
  }

  static redactPII(text) {
    if (typeof text !== 'string') return text;
    return text
      .replace(/\b[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Z|a-z]{2,}\b/g, '[EMAIL]')
      .replace(/\b\d{3}-\d{2}-\d{4}\b/g, '[SSN]')
      .replace(/\b\d{4}[\s-]?\d{4}[\s-]?\d{4}[\s-]?\d{4}\b/g, '[CARD]');
  }
}

// Custom format with integrity signing
const secureFormat = winston.format((info) => {
  const sanitizedInfo = {
    timestamp: new Date().toISOString(),
    level: info.level,
    service: config.serviceName,
    environment: config.environment,
    message: LogSanitizer.sanitizeString(info.message),
    ...LogSanitizer.sanitizeObject(info.metadata || {})
  };

  return signLogEntry(sanitizedInfo);
});

// Production logger with rotation and security
const logger = winston.createLogger({
  level: config.logLevel,
  format: winston.format.combine(
    secureFormat(),
    winston.format.json()
  ),
  defaultMeta: { service: config.serviceName },
  transports: [
    new DailyRotateFile({
      filename: 'logs/app-%DATE%.log',
      datePattern: 'YYYY-MM-DD',
      maxSize: '100m',
      maxFiles: '30d',
      auditFile: 'logs/audit.json'
    }),
    new winston.transports.Console({
      format: winston.format.combine(
        winston.format.colorize(),
        winston.format.simple()
      )
    })
  ],
  exceptionHandlers: [
    new winston.transports.File({ filename: 'logs/exceptions.log' })
  ],
  rejectionHandlers: [
    new winston.transports.File({ filename: 'logs/rejections.log' })
  ]
});

// Security event logger (separate for SIEM)
const securityLogger = winston.createLogger({
  level: 'info',
  format: winston.format.combine(
    secureFormat(),
    winston.format.json()
  ),
  transports: [
    new winston.transports.File({ filename: 'logs/security.log' })
  ]
});

// Request context middleware
app.use((req, res, next) => {
  req.correlationId = req.headers['x-correlation-id'] || uuidv4();
  req.requestId = uuidv4();
  res.setHeader('X-Request-Id', req.requestId);
  res.setHeader('X-Correlation-Id', req.correlationId);

  // Capture response for logging
  const startTime = Date.now();
  res.on('finish', () => {
    logger.info('HTTP Request', {
      metadata: {
        requestId: req.requestId,
        correlationId: req.correlationId,
        method: req.method,
        path: LogSanitizer.sanitizeString(req.path),
        query: LogSanitizer.sanitizeObject(req.query),
        statusCode: res.statusCode,
        responseTime: Date.now() - startTime,
        ip: req.ip,
        userAgent: LogSanitizer.sanitizeString(req.get('User-Agent'))
      }
    });
  });

  next();
});

// Security event logging helper
function logSecurityEvent(eventType, details, req = null) {
  const event = {
    eventType,
    severity: details.severity || 'MEDIUM',
    timestamp: new Date().toISOString(),
    details: LogSanitizer.sanitizeObject(details),
    requestContext: req ? {
      requestId: req.requestId,
      correlationId: req.correlationId,
      ip: req.ip,
      userAgent: LogSanitizer.sanitizeString(req.get('User-Agent'))
    } : null
  };

  securityLogger.warn('Security Event', { metadata: event });
}

// Protected search endpoint
app.get('/api/search', (req, res) => {
  const searchTerm = req.query.q;

  // Detect potential log injection attempts
  if (searchTerm && /[\x00-\x1F\x7F]|\$\{|\{\{/.test(searchTerm)) {
    logSecurityEvent('LOG_INJECTION_ATTEMPT', {
      severity: 'HIGH',
      rawInput: Buffer.from(searchTerm).toString('base64'), // Safe encoding
      action: 'blocked'
    }, req);

    return res.status(400).json({
      error: 'Invalid search query',
      requestId: req.requestId
    });
  }

  logger.info('Search executed', {
    metadata: {
      requestId: req.requestId,
      action: 'search',
      searchTerm: LogSanitizer.sanitizeString(searchTerm),
      resultCount: 0
    }
  });

  res.json({ results: [], requestId: req.requestId });
});

// Authentication with security logging
app.post('/api/auth/login', (req, res) => {
  const { username } = req.body;
  const sanitizedUsername = LogSanitizer.sanitizeString(username);

  // Simulate auth check
  const authSuccess = username === 'validuser';

  if (!authSuccess) {
    logSecurityEvent('FAILED_LOGIN', {
      severity: 'MEDIUM',
      username: sanitizedUsername,
      reason: 'invalid_credentials',
      attemptNumber: 1 // Would track in rate limiter
    }, req);

    return res.status(401).json({
      error: 'Authentication failed',
      requestId: req.requestId
    });
  }

  logger.info('User authenticated', {
    metadata: {
      requestId: req.requestId,
      action: 'login_success',
      username: sanitizedUsername
    }
  });

  res.json({ success: true, requestId: req.requestId });
});

// Health check (minimal logging)
app.get('/health', (req, res) => {
  res.json({ status: 'healthy', timestamp: new Date().toISOString() });
});

// Global error handler with safe logging
app.use((err, req, res, next) => {
  const errorId = uuidv4();

  logger.error('Unhandled error', {
    metadata: {
      errorId,
      requestId: req.requestId,
      correlationId: req.correlationId,
      errorName: err.name,
      errorMessage: LogSanitizer.sanitizeString(err.message),
      stack: config.environment === 'development' 
        ? LogSanitizer.sanitizeString(err.stack) 
        : '[HIDDEN_IN_PROD]'
    }
  });

  res.status(500).json({
    error: 'Internal server error',
    errorId,
    requestId: req.requestId
  });
});

app.listen(3000, () => {
  logger.info('Server started', {
    metadata: {
      port: 3000,
      environment: config.environment,
      service: config.serviceName
    }
  });
});
```

**Defense in Depth Layers**:

1. **Input Sanitization Layer**:
```javascript
// Multi-stage sanitization
const sanitized = input
  .replace(/[\x00-\x1F\x7F]/g, '')         // Control characters
  .replace(/\$\{[^}]*\}/g, '[REMOVED]')    // JNDI expressions (Log4Shell)
  .replace(/\{\{[^}]*\}\}/g, '[REMOVED]')  // Template expressions
  .substring(0, maxLength);                 // Length limit
```

2. **Structured Logging Layer**:
```javascript
// JSON format ensures user input cannot break log structure
logger.info('Event', {
  userInput: maliciousInput  // Becomes JSON value, not log text
});
// Output: {"level":"info","message":"Event","userInput":"malicious\\ncontent"}
```

3. **Log Integrity Layer**:
```javascript
// HMAC signature detects tampering
function verifyLogEntry(entry) {
  const { _signature, ...content } = entry;
  const expected = crypto
    .createHmac('sha256', config.hmacSecret)
    .update(JSON.stringify(content))
    .digest('hex');
  return _signature === expected;
}
```

**Additional Protections**:
- **Correlation IDs**: Track requests across microservices without exposing user data
- **Separate Security Logs**: Security events go to dedicated files for SIEM integration
- **PII Redaction**: Automatically detect and mask emails, SSNs, credit cards
- **Log Rotation**: Prevent disk exhaustion attacks with size/age limits
- **Exception Isolation**: Unhandled exceptions logged separately to prevent log flooding
- **Base64 Encoding**: Store suspicious raw input safely for forensic analysis
- **Environment-Aware**: Stack traces hidden in production, shown in development
- **Rate Detection**: Security events track patterns for anomaly detection
